import LocalAuthentication

class AuthenticationManager {

    static let shared = AuthenticationManager()

    private let context = LAContext()
    private var isAuthenticated = false

    func authenticateUser() {
        let reason = "Authenticate to access your account"

        context.localizedFallbackTitle = "Enter Password"

        context.authenticate(
            self,
            localizedReason: reason,
            reply: { (error: Error?) in
                if let error = error {
                    print("Authentication failed: \(error.localizedDescription)")
                    return
                }

                self.isAuthenticated = true
                UserDefaults.standard.set(true, forKey: "isAuthenticated")
                NotificationCenter.default.post(name: .authenticationSuccess, object: nil)
            }
        )
    }

    func isUserAuthenticated() -> Bool {
        return isAuthenticated || UserDefaults.standard.bool(forKey: "isAuthenticated")
    }
}

extension Notification.Name {
    static let authenticationSuccess = Notification.Name("authenticationSuccess")
